import { describe, it, expect } from 'vitest';
import { createLaceyNestedRng, HELIX_TURN_SAMPLES } from '../lacey-nested-prng';

describe('LaceyNestedRng', () => {
  it('is deterministic for the same seed', () => {
    const a = createLaceyNestedRng(0xdecafbadn);
    const b = createLaceyNestedRng(0xdecafbadn);
    for (let i = 0; i < 32; i++) {
      expect(a.nextU64()).toBe(b.nextU64());
    }
  });

  it('advances step index each draw', () => {
    const r = createLaceyNestedRng(42n);
    expect(r.stepIndex).toBe(0n);
    r.nextU64();
    expect(r.stepIndex).toBe(1n);
  });

  it('produces floats in [0, 1)', () => {
    const r = createLaceyNestedRng(99n);
    for (let i = 0; i < 200; i++) {
      const x = r.nextFloat();
      expect(x).toBeGreaterThanOrEqual(0);
      expect(x).toBeLessThan(1);
      expect(Number.isNaN(x)).toBe(false);
    }
  });

  it('exposes HELIX_TURN_SAMPLES consistent with bitwise-cipher', () => {
    expect(HELIX_TURN_SAMPLES).toBe(11);
  });
});
